	private void InitializeVoice()
	{
		_voiceList = (from o in _prototypeManager.EnumeratePrototypes<TTSVoicePrototype>()
			where o.RoundStart
			orderby Loc.GetString(o.Name)
			select o).ToList();
		VoiceButton.OnItemSelected += delegate(HeadedOptionButton.ItemSelectedEventArgs args)
		{
			TTSVoicePrototype tTSVoicePrototype = _voiceList[args.Id];
			if (IsVoiceLocked(tTSVoicePrototype))
			{
				UpdateTTSVoicesControls();
			}
			else
			{
				VoiceButton.SelectId(args.Id);
				SetVoice(tTSVoicePrototype.ID);
			}
		};
		((BaseButton)VoicePlayButton).OnPressed += delegate
		{
			PlayPreviewTTS();
		};
	}

	private bool IsVoiceLocked(TTSVoicePrototype voice)
	{
		if (string.IsNullOrEmpty(voice.RequiresPermission))
		{
			return false;
		}
		if (_entManager.System<LobbyPermissionsSystem>().Permissions.TryGetValue(voice.RequiresPermission, out var value))
		{
			return value <= 0;
		}
		return true;
	}

	private void UpdateTTSVoicesControls()
	{
		if (Profile == null || !((Control)TTSContainer).Visible)
		{
			return;
		}
		VoiceButton.Clear();
		int num = -1;
		for (int i = 0; i < _voiceList.Count; i++)
		{
			TTSVoicePrototype tTSVoicePrototype = _voiceList[i];
			if (HumanoidCharacterProfile.CanHaveVoice(tTSVoicePrototype, Profile.Sex))
			{
				string text = Loc.GetString(tTSVoicePrototype.Name);
				if (IsVoiceLocked(tTSVoicePrototype))
				{
					text = Loc.GetString("humanoid-profile-editor-voice-locked", new(string, object)[1] { ("voice", text) });
				}
				else if (num == -1)
				{
					num = i;
				}
				VoiceButton.AddItem(text, i);
			}
		}
		int num2 = _voiceList.FindIndex((TTSVoicePrototype x) => x.ID == Profile.Voice);
		if (((num2 >= 0 && IsVoiceLocked(_voiceList[num2])) || !VoiceButton.TrySelectId(num2)) && num >= 0 && VoiceButton.TrySelectId(num))
		{
			SetVoice(_voiceList[num].ID);
		}
		VoiceButton.ResetSearch();
	}

	private void PlayPreviewTTS()
	{
		if (Profile != null)
		{
			_entManager.System<TTSSystem>().RequestPreviewTTS(Profile.Voice);
		}
	}

	private void SetVoice(string newVoice)
	{
		Profile = Profile?.WithVoice(newVoice);
		IsDirty = true;
	}

