	private void InitializeSpecies()
	{
		((BaseButton)HumanButton).OnPressed += delegate
		{
			SetSpecies("Human");
			UpdateSpeciesButtons();
		};
		((BaseButton)FelinidButton).OnPressed += delegate
		{
			if (HasFelinidPermission())
			{
				SetSpecies("Felinid");
				UpdateSpeciesButtons();
			}
		};
		UpdateSpeciesButtons();
	}

	private bool HasFelinidPermission()
	{
		if (_permissions.TryGetValue("UnlockFelinid", out var value))
		{
			return value > 0;
		}
		return false;
	}

	public void UpdatePermissions(Dictionary<string, int> permissions)
	{
		_permissions = new Dictionary<string, int>(permissions);
		UpdateSpeciesButtons();
	}

